  it("should correctly parse stack lines with $ anchor so that named function stack lines do not match attempt2", () => {
    // The mutation removes the $ anchor from attempt2 regex:
    // Original:  /at ([^ ]+):(\d+):(?:\d+)$/
    // Mutated:   /at ([^ ]+):(\d+):(?:\d+)/
    //
    // Without $, a stack line like "at funcName (file.js:10:5)" could match attempt2
    // because "at file.js:10:5" appears within the string (after stripping parens context).
    // Actually, the key difference: a line "at file.js:10:5 (extra)" won't match with $
    // but will match without $.
    //
    // We test this by enabling long stack support and checking that errors
    // propagate correctly through the promise chain, which depends on
    // filterStackString -> isInternalFrame -> getFileNameAndLineNumber working correctly.

    Q.longStackSupport = true;

    try {
