      // The key observable behavior: with the mutation, attempt2 (no $ anchor) can 
      // match lines that contain extra content after the column number.
      // This means a line like "at funcName (file:line:col)" - attempt1 returns []
      // but attempt2 without $ could match "at funcName (file:line:col" partially.

      // We test by creating a promise chain and verifying the error stack
      // contains expected content (long stack traces work correctly)
      const deferred = Q.defer();

      function level1(): Promise<any> {
        return Q().then(() => level2());
      }

      function level2(): Promise<any> {
        return Q.reject(new Error("test error"));
      }

      return level1().then(
