          // The stack should contain our function names
          expect(err.message).toBe("test error");
          // The stack trace should be a string
          expect(typeof err.stack).toBe("string");

          // With the mutation (no $), attempt2 regex without $ anchor would match
          // lines like "at Object.<anonymous> (file.js:1:1)" because the regex
          // /at ([^ ]+):(\d+):(?:\d+)/ would find "at Object" doesn't match but
          // the real issue: it matches "at /abs/path:line:col)" with the trailing ")"
          // included in the filename capture group.
          // 
          // The observable difference: attempt1 for named functions returns []
          // (empty array, not undefined), causing isInternalFrame to return false.
          // attempt2 without $ would match lines ending with extra chars,
          // capturing the trailing ")" as part of filename.
          // This means qFileName comparison fails differently.
          //
          // Most reliable check: the stack trace should include "From previous event"
